-- Add new columns to sinistri table for realistic claims management
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS tipo_sinistro text;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS luogo_sinistro text;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS data_evento date;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS costo_preventivato numeric DEFAULT 0;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS costo_effettivo numeric DEFAULT 0;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS franchigia numeric DEFAULT 0;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS importo_liquidato numeric DEFAULT 0;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS importo_riserva numeric DEFAULT 0;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS targa_veicolo text;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS controparte text;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS note_perito text;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS numero_sinistro_compagnia text;
ALTER TABLE sinistri ADD COLUMN IF NOT EXISTS cliente_anagrafica_id uuid REFERENCES clienti(id);

