-- Insert default checklist for new sinistri
INSERT INTO sinistro_checklist (sinistro_id, descrizione, obbligatorio, completato)
SELECT s.id, item.descrizione, item.obbligatorio,
  CASE WHEN s.stato IN ('chiuso','respinto') THEN true ELSE (random() > 0.4) END
FROM sinistri s
CROSS JOIN (VALUES
  ('Denuncia sinistro compilata', true),
  ('Documentazione fotografica', true),
  ('Copia polizza allegata', true),
  ('Modulo CID/CAI compilato', false)
) AS item(descrizione, obbligatorio)
WHERE s.numero_sinistro LIKE 'SIN-202%'
  AND NOT EXISTS (SELECT 1 FROM sinistro_checklist sc WHERE sc.sinistro_id = s.id);

-- Insert eventi for some sinistri
INSERT INTO sinistro_eventi (sinistro_id, tipo_evento, data_scadenza, stato, note)
SELECT s.id, ev.tipo_evento, ev.data_scadenza::date, ev.stato, ev.note
FROM sinistri s
CROSS JOIN LATERAL (VALUES
  ('perizia', (s.data_apertura + 15)::text, CASE WHEN s.stato IN ('chiuso','respinto') THEN 'completato' ELSE 'attivo' END, 'Perizia danni programmata'),
  ('attesa_documento', (s.data_apertura + 30)::text, CASE WHEN s.stato IN ('chiuso','respinto') THEN 'completato' WHEN s.data_apertura + 30 < CURRENT_DATE THEN 'scaduto' ELSE 'attivo' END, 'Documentazione integrativa richiesta')
) AS ev(tipo_evento, data_scadenza, stato, note)
WHERE s.numero_sinistro LIKE 'SIN-202%'
  AND NOT EXISTS (SELECT 1 FROM sinistro_eventi se WHERE se.sinistro_id = s.id);